    "json": "{\n    \"id\": \"soft-green-graduation-story\",\n    \"name\": \"تهنئة تخرج خضراء ناعمة\",\n    \"version\": \"1.0.0\",\n    \"html\": \"index.html\",\n    \"css\": \"style.css\",\n    \"settings\": {\n        \"exportable\": true,\n        \"hasAnimation\": false,\n        \"width\": 1080,\n        \"height\": 1920,\n        \"durationSeconds\": 5\n    },\n    \"fields\": [\n        {\n            \"key\": \"topText\",\n            \"type\": \"textarea\",\n            \"required\": true,\n            \"defaultValue\": \"في العصر أيام يزينها السرور\\nوسرور هذا اليوم جدا مختلف\",\n            \"label\": \"النص العلوي\",\n            \"minLength\": 5,\n            \"maxLength\": 140\n        },\n        {\n            \"key\": \"middleText\",\n            \"type\": \"textarea\",\n            \"required\": true,\n            \"defaultValue\": \"يسعدنا أن تشاركونا فرحتنا بتخرج\",\n            \"label\": \"نص قبل الاسم\",\n            \"minLength\": 3,\n            \"maxLength\": 120\n        },\n        {\n            \"key\": \"name\",\n            \"type\": \"text\",\n            \"required\": true,\n            \"label\": \"اسم الخريج / الخريجة\",\n            \"placeholder\": \"مثال: سارة\",\n            \"minLength\": 2,\n            \"maxLength\": 50\n        },\n        {\n            \"key\": \"bottomText\",\n            \"type\": \"textarea\",\n            \"required\": true,\n            \"defaultValue\": \"لقاؤكم المحب يزيد أنساً\\nفتقربكم المسرة والسعادة\",\n            \"label\": \"النص السفلي\",\n            \"minLength\": 5,\n            \"maxLength\": 140\n        }\n    ]\n}",
    "html": "<!DOCTYPE html>\n<html lang=\"ar\" dir=\"rtl\">\n\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>بطاقة تهنئة تخرج</title>\n    <link rel=\"stylesheet\" href=\"style.css\">\n</head>\n\n<body>\n    <main class=\"graduation-story\" style=\"background-image: url('assets/images/bg.png');\">\n        <section class=\"text-area\">\n            <p class=\"top-text\">{{topText}}</p>\n            <p class=\"middle-text\">{{middleText}}</p>\n            <h1 class=\"graduate-name\">{{name}}</h1>\n            <p class=\"bottom-text\">{{bottomText}}</p>\n        </section>\n    </main>\n</body>\n\n</html>",
    "css": "@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800;900&display=swap');\n\n:root {\n    --text-color: #3f5f58;\n    --name-color: #72a99b;\n}\n\nhtml,\nbody {\n    width: 100%;\n    height: 100%;\n    margin: 0;\n    overflow: hidden;\n}\n\nbody {\n    direction: rtl;\n    font-family: \"Tajawal\", Arial, sans-serif;\n    background: #f7f8f5;\n    display: grid;\n    place-items: center;\n    -webkit-font-smoothing: antialiased;\n    text-rendering: geometricPrecision;\n}\n\n.graduation-story {\n    position: relative;\n\n    width: min(100vw, calc(100dvh * 9 / 16));\n    height: min(100dvh, calc(100vw * 16 / 9));\n\n    overflow: hidden;\n    container-type: size;\n    background-size: 100% 100%;\n    background-position: center;\n    background-repeat: no-repeat;\n\n    color: var(--text-color);\n}\n\n/* مكان النص مضبوط بناء على أبعاد 1080x1920 */\n.text-area {\n    position: absolute;\n    top: 22.5cqh;\n    left: 50%;\n    transform: translateX(-50%);\n\n    width: 74cqw;\n\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n\n    text-align: center;\n    color: var(--text-color);\n}\n\n.top-text,\n.middle-text,\n.bottom-text {\n    margin: 0;\n\n    color: var(--text-color);\n    font-family: \"Tajawal\", Arial, sans-serif;\n    font-size: 3.35cqw;\n    font-weight: 700;\n    line-height: 1.75;\n    letter-spacing: 0.02em;\n\n    white-space: pre-line;\n    text-wrap: balance;\n    overflow-wrap: anywhere;\n}\n\n.middle-text {\n    margin-top: 8.2cqh;\n}\n\n.graduate-name {\n    margin: 2.5cqh 0 5.3cqh;\n    color: var(--name-color);\n    font-family: \"Tajawal\", Arial, sans-serif;\n    font-size: 8.6cqw;\n    font-weight: 900;\n    line-height: 1.05;\n    letter-spacing: -0.03em;\n    text-wrap: balance;\n    overflow-wrap: anywhere;\n}\n\n.bottom-text {\n    max-width: 66cqw;\n}\n\n/* تصدير وطباعة */\n@media print {\n    @page {\n        margin: 0;\n        size: 1080px 1920px;\n    }\n\n    html,\n    body {\n        width: 1080px;\n        height: 1920px;\n        overflow: hidden;\n        -webkit-print-color-adjust: exact;\n        print-color-adjust: exact;\n    }\n\n    .graduation-story {\n        width: 1080px;\n        height: 1920px;\n    }\n}"
