    "json": "{\n    \"id\": \"royal-wedding\",\n    \"name\": \"دعوة زفاف ملكية\",\n    \"version\": \"1.0.0\",\n    \"html\": \"index.html\",\n    \"css\": \"style.css\",\n    \"fields\": [\n        {\n            \"maxLength\": 120,\n            \"required\": true,\n            \"type\": \"text\",\n            \"label\": \"الاسم\",\n            \"key\": \"name\"\n        }\n    ]\n}",
    "html": "<!DOCTYPE html>\n<html lang=\"en\">\n\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Document</title>\n    <link rel=\"stylesheet\" href=\"style.css\">\n</head>\n\n<body>\n    <div class=\"eid-card\"\n        style=\"background-image: url('data:image/jpeg;base64,');\">\n        <div class=\"name\">{{ name }}</div>\n    </div>\n</body>\n\n</html>",
    "css": "@import url('https://fonts.googleapis.com/css2?family=Beiruti:wght@200..900&family=Tajawal:wght@200;300;400;500;700;800;900&display=swap');\n\nbody {\n    margin: 0;\n    padding: 0;\n}\n\n.eid-card {\n    position: relative;\n    width: min(100%, 430px);\n    aspect-ratio: 736 / 1308;\n\n    background-size: cover;\n    background-position: center;\n    background-repeat: no-repeat;\n}\n\n.name {\n    position: absolute;\n    top: 71.8%;\n    left: 50%;\n    transform: translateX(-50%);\n    width: 38%;\n    text-align: center;\n    font-family: 'Tajawal', sans-serif;\n    font-size: clamp(14px, 4vw, 24px);\n    font-weight: 600;\n    color: #173b49;\n}"
